30: /**
31:  * A timestamp assigner and watermark generator for streams where timestamps are monotonously
32:  * ascending. In this case, the local watermarks for the streams are easy to generate, because they
33:  * strictly follow the timestamps.
34:  *
35:  * @param <T> The type of the elements that this function can extract timestamps from
36:  */
37: @Deprecated
38: @PublicEvolving
39: public abstract class AscendingTimestampExtractor<T>
40:         implements WatermarkStrategyWithPeriodicWatermarks<T> {
41: 
42:     private static final long serialVersionUID = 1L;
43: 
44:     /** The current timestamp. */
45:     private long currentTimestamp = Long.MIN_VALUE;
46: 
47:     /** Handler that is called when timestamp monotony is violated. */
48:     private MonotonyViolationHandler violationHandler = new LoggingHandler();
49: 
50:     /**
51:      * Extracts the timestamp from the given element. The timestamp must be monotonically
52:      * increasing.
53:      *
54:      * @param element The element that the timestamp is extracted from.
55:      * @return The new timestamp.
56:      */
57:     public abstract long extractAscendingTimestamp(T element);
58: 
59:     /**
60:      * Sets the handler for violations to the ascending timestamp order.
61:      *
62:      * @param handler The violation handler to use.
63:      * @return This extractor.
64:      */
65:     public AscendingTimestampExtractor<T> withViolationHandler(MonotonyViolationHandler handler) {
66:         this.violationHandler = requireNonNull(handler);
67:         return this;
68:     }
69: 
70:     // ------------------------------------------------------------------------
71: 
72:     @Override
73:     public final long extractTimestamp(T element, long elementPrevTimestamp) {
74:         final long newTimestamp = extractAscendingTimestamp(element);
75:         if (newTimestamp >= this.currentTimestamp) {
76:             this.currentTimestamp = newTimestamp;
77:             return newTimestamp;
78:         } else {
79:             violationHandler.handleViolation(newTimestamp, this.currentTimestamp);
80:             return newTimestamp;
81:         }
82:     }
83: 
84:     @Override
85:     public final Watermark getCurrentWatermark() {
86:         return new Watermark(
87:                 currentTimestamp == Long.MIN_VALUE ? Long.MIN_VALUE : currentTimestamp - 1);
88:     }
89: 
90:     // ------------------------------------------------------------------------
91:     //  Handling violations of monotonous timestamps
92:     // ------------------------------------------------------------------------
93: 
94:     /**
95:      * Interface for handlers that handle violations of the monotonous ascending timestamps
96:      * property.
97:      */
98:     public interface MonotonyViolationHandler extends java.io.Serializable {
99: 
100:         /**
101:          * Called when the property of monotonously ascending timestamps is violated, i.e., when
102:          * {@code elementTimestamp < lastTimestamp}.
103:          *
104:          * @param elementTimestamp The timestamp of the current element.
105:          * @param lastTimestamp The last timestamp.
106:          */
107:         void handleViolation(long elementTimestamp, long lastTimestamp);
108:     }
109: 
110:     /** Handler that does nothing when timestamp monotony is violated. */
111:     public static final class IgnoringHandler implements MonotonyViolationHandler {
112:         private static final long serialVersionUID = 1L;
113: 
114:         @Override
115:         public void handleViolation(long elementTimestamp, long lastTimestamp) {}
116:     }
117: 
118:     /** Handler that fails the program when timestamp monotony is violated. */
119:     public static final class FailingHandler implements MonotonyViolationHandler {
120:         private static final long serialVersionUID = 1L;
121: 
122:         @Override
123:         public void handleViolation(long elementTimestamp, long lastTimestamp) {
124:             throw new RuntimeException(
125:                     "Ascending timestamps condition violated. Element timestamp "
126:                             + elementTimestamp
127:                             + " is smaller than last timestamp "
128:                             + lastTimestamp);
129:         }
130:     }
131: 
132:     /** Handler that only logs violations of timestamp monotony, on WARN log level. */
133:     public static final class LoggingHandler implements MonotonyViolationHandler {
134:         private static final long serialVersionUID = 1L;
135: 
136:         private static final Logger LOG =
137:                 LoggerFactory.getLogger(AscendingTimestampExtractor.class);
138: 
139:         @Override
140:         public void handleViolation(long elementTimestamp, long lastTimestamp) {
141:             LOG.warn("Timestamp monotony violated: {} < {}", elementTimestamp, lastTimestamp);
142:         }
143:     }
144: }
